def gen_maps(r):
    r=tuple(r)
    outs=[]
    def add(name,out,params):
        outs.append((name,sort_tuple(out),params))
    # map1
    maxa=max(0,r[2]-r[1])
    for a in np.linspace(0,maxa,6):
        add('snake1',(r[0],r[1],r[2]-a,r[3]+a),{'a':a})
    # map2
    maxa=max(0,min((r[3]-r[2])/2, r[1]-r[0]))
    for a in np.linspace(0,maxa,6):
        add('codim',(r[0],r[1]-a,r[2]+a,r[3]-a),{'a':a})
    # map3 main
    maxa=max(0,min((r[1]-r[0])/4,(r[3]-r[2])/2))
    for a in np.linspace(0,maxa,6):
        add('short-main',(r[0]+a,r[1]-3*a,r[2]+a,r[3]-a),{'a':a})
    # tech
    maxa=max(0,(r[1]-r[0])/4)
    for a in np.linspace(0,maxa,6):
        add('short-tech',(r[0]+a,r[1]-3*a,r[2],r[3]),{'a':a})
    # pinch sample alpha < r0, beta max, require target maybe alpha<=beta, no order issue
    for alpha in np.linspace(r[0]-4, r[0], 5)[:-1]:
        beta_max=r[1]+r[2]+r[3]-2*alpha
        for beta in np.linspace(alpha, beta_max, 5):
            add('pinch',(alpha,alpha,alpha,beta),{'alpha':alpha,'beta':beta,'beta_max':beta_max})
    # double
    amin=r[0]; amax=(r[1]+r[2])/2
    if amax>amin:
      for alpha in np.linspace(amin, amax, 5)[1:-1]:
        beta_max=sum(r)-3*alpha
        if beta_max>=alpha:
            for beta in np.linspace(alpha,beta_max,4):
                add('double',(r[0]-alpha,alpha,alpha,beta),{'alpha':alpha,'beta':beta,'beta_max':beta_max})
    return outs

