def random_map(r):
    r=tuple(r)
    maps=[]
    # choose type randomly with valid params
    typ=random.choice(['snake1','codim','short-main','short-tech','pinch','double'])
    if typ=='snake1':
        maxa=max(0,r[2]-r[1]); a=random.random()*maxa
        return typ, sort_tuple((r[0],r[1],r[2]-a,r[3]+a)), {'a':a}
    if typ=='codim':
        maxa=max(0,min((r[3]-r[2])/2, r[1]-r[0])); a=random.random()*maxa
        return typ, sort_tuple((r[0],r[1]-a,r[2]+a,r[3]-a)), {'a':a}
    if typ=='short-main':
        maxa=max(0,min((r[1]-r[0])/4,(r[3]-r[2])/2)); a=random.random()*maxa
        return typ, sort_tuple((r[0]+a,r[1]-3*a,r[2]+a,r[3]-a)), {'a':a}
    if typ=='short-tech':
        maxa=max(0,(r[1]-r[0])/4); a=random.random()*maxa
        return typ, sort_tuple((r[0]+a,r[1]-3*a,r[2],r[3])), {'a':a}
    if typ=='pinch':
        # choose alpha below r0 by up to range, beta between alpha and max
        alpha=r[0]-random.expovariate(1)
        beta_max=r[1]+r[2]+r[3]-2*alpha
        beta=alpha+random.random()*max(0,beta_max-alpha)
        return typ, sort_tuple((alpha,alpha,alpha,beta)), {'alpha':alpha,'beta':beta}
    if typ=='double':
        amin=r[0]; amax=(r[1]+r[2])/2
        if amax<=amin: return 'id',r,{}
        alpha=amin+random.random()*(amax-amin)
        beta_max=sum(r)-3*alpha
        if beta_max<alpha: beta=alpha
        else: beta=alpha+random.random()*(beta_max-alpha)
        return typ, sort_tuple((2*r[0]-alpha,alpha,alpha,beta)), {'alpha':alpha,'beta':beta}

